#!/usr/bin/env python3
"""
encode-real-model-streaming.py — Streaming GKQ v2 encoder for big models.

Same I/O contract as `encode-real-model.py` but loads ONE tensor at a time
from HuggingFace safetensors shards instead of materializing the full
model.state_dict() in RAM. Peak RAM is bounded by the largest single tensor
(typically the embedding) plus a small SVD working buffer — adequate for
encoding Gemma4-31B or Llama-70B on a workstation that could never hold
the whole model.

Usage:
    python3 encode-real-model-streaming.py \
        --model Qwen/Qwen2.5-0.5B-Instruct \
        --output /tmp/qwen-streaming.knot \
        --rank 64

    python3 encode-real-model-streaming.py \
        --model ./local-dir-with-safetensors \
        --output out.knot --rank 64 --max-layers 4

Regression contract: at the same `--rank`, output is byte-identical to the
non-streaming `encode-real-model.py` for any model that fits in RAM with
the legacy loader. The math is identical; only the I/O path changes.
"""

from __future__ import annotations

import argparse
import json
import os
import sys
from pathlib import Path
from typing import Dict, List, Optional, Tuple

import numpy as np

# Local helpers — reuse mapping + writer + spectral quantizer from the
# non-streaming encoder (DRY; if the math drifts, both must drift together).
_HERE = Path(__file__).resolve().parent
sys.path.insert(0, str(_HERE))
import gkq_v2_format as gkq  # noqa: E402

# Lifted from encode-real-model.py — single source of truth for name mapping,
# arch detection, KnotConfig construction, and the SVD/uint8 quantization
# kernel. If you change those, change them THERE and the streaming encoder
# inherits the fix automatically.
import importlib.util  # noqa: E402

_legacy_spec = importlib.util.spec_from_file_location(
    "encode_real_model_legacy", str(_HERE / "encode-real-model.py")
)
_legacy = importlib.util.module_from_spec(_legacy_spec)
_legacy_spec.loader.exec_module(_legacy)  # type: ignore[union-attr]

map_tensor_name = _legacy.map_tensor_name
detect_arch = _legacy.detect_arch
build_knot_config = _legacy.build_knot_config
_spectral_quantize = _legacy._spectral_quantize
_sketch_quantize = _legacy._sketch_quantize
_should_sketch = _legacy._should_sketch

import sketch_knot_format as skf  # noqa: E402


# ─────────────────────────────────────────────────────────────────────────────
# Safetensors shard discovery
# ─────────────────────────────────────────────────────────────────────────────


def _resolve_model_dir(model_arg: str, cache_dir: str) -> Path:
    """If `model_arg` is a local directory with safetensors, return it.
    Otherwise treat it as a HF id and snapshot_download safetensors + JSON.
    """
    p = Path(model_arg)
    if p.is_dir() and any(p.glob("*.safetensors")):
        print(f"[hf] using local model dir: {p}")
        return p

    try:
        from huggingface_hub import snapshot_download
    except Exception as e:
        print(
            "ERROR: huggingface_hub not available; cannot resolve HF id.\n"
            f"  {e}\n"
            "Install with: pip3 install --user huggingface_hub safetensors",
            file=sys.stderr,
        )
        raise

    cache = Path(cache_dir)
    cache.mkdir(parents=True, exist_ok=True)
    print(f"[hf] snapshot_download {model_arg} → {cache}")
    local = snapshot_download(
        repo_id=model_arg,
        cache_dir=str(cache),
        allow_patterns=["*.safetensors", "*.safetensors.index.json", "config.json"],
    )
    return Path(local)


def _load_shard_map(model_dir: Path) -> Dict[str, str]:
    """Return tensor_name → absolute shard path.

    Uses `model.safetensors.index.json` when present (multi-shard models).
    Falls back to enumerating every `*.safetensors` file in the dir, listing
    each tensor it contains, and stitching the map by hand.
    """
    from safetensors import safe_open  # local import

    index = model_dir / "model.safetensors.index.json"
    if index.exists():
        with open(index) as f:
            idx = json.load(f)
        weight_map = idx.get("weight_map", {})
        # Values are relative shard names; resolve to absolute paths.
        out: Dict[str, str] = {}
        for tname, shard_rel in weight_map.items():
            out[tname] = str(model_dir / shard_rel)
        print(f"[hf] shard index: {len(out)} tensors across "
              f"{len(set(out.values()))} shards")
        return out

    # No index — enumerate every safetensors file manually.
    shards = sorted(model_dir.glob("*.safetensors"))
    if not shards:
        raise FileNotFoundError(f"no *.safetensors under {model_dir}")
    out = {}
    for shard in shards:
        with safe_open(str(shard), framework="pt", device="cpu") as f:
            for tname in f.keys():
                if tname in out:
                    raise ValueError(
                        f"duplicate tensor {tname!r} in {shard} and {out[tname]}"
                    )
                out[tname] = str(shard)
    print(f"[hf] enumerated {len(out)} tensors across {len(shards)} shard(s)")
    return out


def _load_hf_config(model_dir: Path):
    """Load the model config object so detect_arch / build_knot_config (both
    use getattr) work consistently.

    Prefers `transformers.AutoConfig` when available because the legacy
    encoder uses it and we need byte-identical metadata to pass the
    regression test (transformers filters/normalizes some fields — e.g.
    Qwen2 drops `rope_theta` and `sliding_window` — and the legacy
    encoder's `build_knot_config` falls back to its hardcoded defaults
    when those attributes are missing).

    Falls back to a raw `config.json` namespace if transformers is not
    installed; in that case the file's `knot_config` metadata will reflect
    the raw values from the model card, which is semantically MORE correct
    but will not byte-match a legacy file produced by the same model.
    """
    cfg_path = model_dir / "config.json"
    if not cfg_path.exists():
        raise FileNotFoundError(f"missing config.json in {model_dir}")

    try:
        from transformers import AutoConfig  # type: ignore
        cfg = AutoConfig.from_pretrained(str(model_dir))
        print("[stream] config: transformers.AutoConfig (matches legacy encoder)")
        return cfg
    except Exception as e:
        print(f"[stream] config: raw config.json fallback ({e})")

    with open(cfg_path) as f:
        cfg_dict = json.load(f)

    class _Cfg:  # minimal stand-in for AutoConfig
        pass

    cfg = _Cfg()
    for k, v in cfg_dict.items():
        setattr(cfg, k, v)
    return cfg


# ─────────────────────────────────────────────────────────────────────────────
# Streaming tensor fetch
# ─────────────────────────────────────────────────────────────────────────────


def _bf16_bytes_to_f32(buf: bytes, shape) -> np.ndarray:
    """Exact bf16 → f32 promotion via 16-bit shift into the high half of f32."""
    bf = np.frombuffer(buf, dtype=np.uint16)
    f32 = np.zeros(bf.size, dtype=np.uint32)
    f32[:] = bf.astype(np.uint32) << 16
    return f32.view(np.float32).reshape(shape)


def _fetch_tensor_as_f32(shard_path: str, tensor_name: str) -> np.ndarray:
    """Load one tensor from a safetensors shard and return it as a numpy f32.

    bf16 is promoted exactly (bf16 occupies the high 16 bits of an f32, so
    shifting in zeros yields a lossless cast). f16 stays as f16 only if the
    caller asks for it; here we always return f32 because that's what the
    SVD kernel and the legacy encoder both work in.
    """
    from safetensors import safe_open  # local import

    with safe_open(shard_path, framework="pt", device="cpu") as f:
        t = f.get_tensor(tensor_name)
    # torch path: cast to f32 if needed, then numpy.
    import torch
    if t.dtype == torch.bfloat16:
        t = t.to(torch.float32)
    elif t.dtype == torch.float16:
        # Match the legacy encoder which preserves f16 for *dense* tensors
        # but always upcasts for spectral. Caller decides via use site.
        return t.cpu().numpy()
    arr = t.detach().cpu().numpy()
    return arr


def _fetch_tensor_preserve_dtype(shard_path: str, tensor_name: str) -> np.ndarray:
    """Same as _fetch_tensor_as_f32 but keeps f16 as f16 (matches legacy
    dense-write code path which checks `if arr.dtype == np.float16: pass`)."""
    from safetensors import safe_open
    import torch
    with safe_open(shard_path, framework="pt", device="cpu") as f:
        t = f.get_tensor(tensor_name)
    if t.dtype == torch.bfloat16:
        t = t.to(torch.float32)
    return t.detach().cpu().numpy()


# ─────────────────────────────────────────────────────────────────────────────
# Streaming encode (mirrors encode_state_dict but never holds >1 tensor)
# ─────────────────────────────────────────────────────────────────────────────


def encode_streaming(
    *,
    model_dir: Path,
    model_name: str,
    output_path: str,
    max_layers: Optional[int],
    rank: int,
    sketch_rank: Optional[int] = None,
    sketch_output_path: Optional[str] = None,
) -> dict:
    """Pass 1: inventory tensors (no payloads). Pass 2: stream-encode."""
    # ── Pass 1: config + tensor inventory ────────────────────────────────────
    hf_config = _load_hf_config(model_dir)
    arch = detect_arch(hf_config)
    knot_config = build_knot_config(hf_config, arch, max_layers)
    tie_word_embeddings = bool(getattr(hf_config, "tie_word_embeddings", False))

    shard_map = _load_shard_map(model_dir)  # tensor_name → shard path
    print(f"[stream] arch={arch} tie_word_embeddings={tie_word_embeddings} "
          f"num_layers(config)={knot_config['num_layers']}")

    # Classify every shard tensor → (canonical, kind). Skip layers > max.
    # We don't load any payload here; we only need the names.
    classified: List[Tuple[str, str, str]] = []  # (canonical, kind, hf_name)
    seen_canonical: Dict[str, Tuple[str, str]] = {}  # canonical → (hf_name, kind)

    for hf_name in shard_map:
        mapped = map_tensor_name(hf_name, max_layers)
        if mapped is None:
            continue
        canonical, kind = mapped
        if canonical in seen_canonical:
            continue
        seen_canonical[canonical] = (hf_name, kind)
        classified.append((canonical, kind, hf_name))

    # ── Tied embeddings ──────────────────────────────────────────────────────
    # Mirror legacy logic. Without `from_pretrained`, we cannot use data_ptr;
    # we rely on the `tie_word_embeddings` config flag. For Qwen2.5 / Gemma2
    # this matches the legacy encoder's data_ptr check because HF stores only
    # one of the two when ties are active.
    aliases: List[Tuple[str, str]] = []
    embed_canon = "token_embd.weight"
    out_canon = "output.weight"
    if tie_word_embeddings:
        embed_in = embed_canon in seen_canonical
        out_in = out_canon in seen_canonical
        if embed_in and not out_in:
            # Most common case: HF safetensors omits lm_head when tied.
            aliases.append((out_canon, embed_canon))
            seen_canonical[out_canon] = ("model.embed_tokens.weight", "dense")
            print(f"[stream] tied weights (config flag): "
                  f"aliasing {out_canon} → {embed_canon}")
        elif embed_in and out_in:
            # Both present — drop the duplicate from classified, emit alias.
            before = len(classified)
            classified = [(c, k, h) for c, k, h in classified if c != out_canon]
            if len(classified) < before:
                aliases.append((out_canon, embed_canon))
                print(f"[stream] tied weights (config flag, both present): "
                      f"aliasing {out_canon} → {embed_canon}")

    num_spectral = sum(1 for _, k, _ in classified if k == "spectral")
    num_dense_full = sum(1 for _, k, _ in classified if k == "dense")
    num_dense = num_dense_full + len(aliases)
    print(f"[stream] classified {len(classified)} tensors: "
          f"{num_spectral} spectral, {num_dense_full} dense + {len(aliases)} alias")
    print(f"[stream] spectral rank: {rank}")

    # ── Pass 2: stream encode ────────────────────────────────────────────────
    # Sort to match the legacy encoder's deterministic write order
    # (spectral by canonical name, then dense by canonical name, then aliases
    # by alias name).
    spectral_items = sorted(
        [(c, h) for c, k, h in classified if k == "spectral"], key=lambda x: x[0]
    )
    dense_items = sorted(
        [(c, h) for c, k, h in classified if k == "dense"], key=lambda x: x[0]
    )

    worst_err = 0.0
    worst_err_name = ""
    spectral_bytes = 0
    dense_bytes = 0
    out_path = Path(output_path)
    out_path.parent.mkdir(parents=True, exist_ok=True)

    # Sketch accumulator (Phase A — Standing-Wave Mesh). When sketch_rank is
    # set, we collect a SketchEntry for each tensor matching SKETCH_NAME_PATTERNS
    # as we walk through them and write a sibling sketches.knot at the end.
    sketches: List[skf.SketchEntry] = []
    do_sketches = sketch_rank is not None and sketch_rank > 0
    if do_sketches:
        print(f"[stream] sketches enabled: rank={sketch_rank} — writing sibling sketches.knot")

    with open(out_path, "wb") as f:
        gkq.write_header(f, model_name, arch, knot_config, num_spectral, num_dense)

        # Spectral: SVD + quantize one tensor at a time, then drop the ref.
        for canonical, hf_name in spectral_items:
            shard = shard_map[hf_name]
            arr = _fetch_tensor_as_f32(shard, hf_name)
            arr = np.ascontiguousarray(arr, dtype=np.float32)
            if arr.ndim != 2:
                arr = arr.reshape(arr.shape[0], -1)
            # Sketch FIRST (so we can release the main quant outputs early).
            if do_sketches and _should_sketch(canonical):
                sk = _sketch_quantize(arr, rank=int(sketch_rank))
                sk.name = canonical
                sketches.append(sk)
            (u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max,
             d_out, d_in, rel_err, eff_rank) = _spectral_quantize(arr, rank=rank)
            del arr  # release immediately
            if rel_err > worst_err:
                worst_err = rel_err
                worst_err_name = canonical
            before = f.tell()
            gkq.write_spectral_tensor(
                f, canonical, u_q8, sigma_q8, v_q8,
                u_max, sigma_max, v_max, d_out, d_in, rank=eff_rank,
            )
            spectral_bytes += f.tell() - before
            del u_q8, sigma_q8, v_q8

        # Dense full blocks (sorted). Preserve f16 when present.
        for canonical, hf_name in dense_items:
            shard = shard_map[hf_name]
            arr = _fetch_tensor_preserve_dtype(shard, hf_name)
            if arr.dtype == np.float16:
                pass
            elif arr.dtype == np.float32:
                pass
            else:
                arr = arr.astype(np.float32)
            arr = np.ascontiguousarray(arr)
            # Sketch the 2D dense tensors we care about (lm_head, token_embd).
            if do_sketches and _should_sketch(canonical) and arr.ndim == 2:
                # SVD requires f32; promote temporarily if dense was f16.
                arr_f32 = arr.astype(np.float32, copy=False) if arr.dtype == np.float16 else arr
                sk = _sketch_quantize(arr_f32, rank=int(sketch_rank))
                sk.name = canonical
                sketches.append(sk)
            before = f.tell()
            gkq.write_dense_tensor(f, canonical, arr)
            dense_bytes += f.tell() - before
            del arr

        # Aliases (sorted). For sketches, alias names get their own SketchEntry
        # cloned off the target so cobordism can look up by canonical alias.
        sketches_by_name = {s.name: s for s in sketches}
        for alias_name, alias_target in sorted(aliases):
            before = f.tell()
            gkq.write_dense_alias(f, alias_name, alias_target)
            dense_bytes += f.tell() - before
            if do_sketches and _should_sketch(alias_name) and alias_target in sketches_by_name \
                    and alias_name not in sketches_by_name:
                src = sketches_by_name[alias_target]
                clone = skf.SketchEntry(
                    name=alias_name,
                    d_out=src.d_out, d_in=src.d_in, rank=src.rank,
                    u_q8=src.u_q8.copy(), sigma_q8=src.sigma_q8.copy(), v_q8=src.v_q8.copy(),
                    u_max=src.u_max, sigma_max=src.sigma_max, v_max=src.v_max,
                )
                sketches.append(clone)

    file_size = out_path.stat().st_size
    summary = {
        "output_path": str(out_path),
        "file_size_bytes": file_size,
        "file_size_mb": file_size / 1e6,
        "num_spectral": num_spectral,
        "num_dense": num_dense,
        "spectral_bytes": spectral_bytes,
        "dense_bytes": dense_bytes,
        "spectral_pct": 100.0 * spectral_bytes / max(file_size, 1),
        "dense_pct": 100.0 * dense_bytes / max(file_size, 1),
        "worst_reconstruction_error": worst_err,
        "worst_reconstruction_error_name": worst_err_name,
    }

    if do_sketches:
        sketch_out = Path(sketch_output_path) if sketch_output_path \
            else out_path.with_name(out_path.stem + "-sketches.knot")
        sketch_out.parent.mkdir(parents=True, exist_ok=True)
        sk_summary = skf.write_sketches_knot(
            str(sketch_out),
            model_name=model_name,
            source_config=knot_config,
            sketches=sketches,
            sketch_rank_default=int(sketch_rank),
        )
        print(f"[stream] sketches: {sk_summary['num_sketches']} entries, "
              f"{sk_summary['file_size_mb']:.2f} MB → {sketch_out}")
        summary["sketches"] = sk_summary

    return summary


def _print_summary(s: dict) -> None:
    print("─" * 64)
    print(f"GKQ v2 file written: {s['output_path']}")
    print(f"  size:               {s['file_size_mb']:.2f} MB ({s['file_size_bytes']:,} bytes)")
    print(f"  spectral tensors:   {s['num_spectral']}  "
          f"({s['spectral_pct']:.1f}% of file, {s['spectral_bytes']:,} bytes)")
    print(f"  dense tensors:      {s['num_dense']}  "
          f"({s['dense_pct']:.1f}% of file, {s['dense_bytes']:,} bytes)")
    print(f"  worst SVD rel-err:  {s['worst_reconstruction_error']:.4f}  "
          f"({s['worst_reconstruction_error_name']})")
    print("─" * 64)


# ─────────────────────────────────────────────────────────────────────────────
# CLI
# ─────────────────────────────────────────────────────────────────────────────


def parse_args(argv=None):
    p = argparse.ArgumentParser(
        description="Streaming GKQ v2 encoder — one tensor at a time from safetensors."
    )
    p.add_argument("--model", required=True,
                   help="HF model id (e.g. google/gemma-2-2b-it) or local dir with safetensors")
    p.add_argument("--output", required=True, help="Output .knot path")
    p.add_argument("--model-name", default=None,
                   help="Override model name stored in the header (default: --model value)")
    p.add_argument("--max-layers", type=int, default=None,
                   help="Encode only the first N transformer layers")
    p.add_argument("--rank", type=int, default=gkq.RANK_DEFAULT,
                   help=f"Spectral rank per weight matrix (default: {gkq.RANK_DEFAULT})")
    p.add_argument("--cache-dir", default="/tmp/hf-cache",
                   help="HF snapshot cache dir (used when --model is a hub id)")
    p.add_argument("--with-exclusion-sketch", type=int, default=None, metavar="RANK",
                   help=("Also write a sibling `<output>-sketches.knot` with rank-K "
                         "exclusion sketches (Phase A — Standing-Wave Mesh)."))
    p.add_argument("--sketch-output", default=None,
                   help="Override sibling sketch output path (default: <stem>-sketches.knot)")
    return p.parse_args(argv)


def main(argv=None) -> int:
    args = parse_args(argv)
    model_dir = _resolve_model_dir(args.model, args.cache_dir)
    summary = encode_streaming(
        model_dir=model_dir,
        model_name=args.model_name or args.model,
        output_path=args.output,
        max_layers=args.max_layers,
        rank=args.rank,
        sketch_rank=args.with_exclusion_sketch,
        sketch_output_path=args.sketch_output,
    )
    _print_summary(summary)
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
